def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        temp_ratio = ratio
        for j in range(5):
            if temp_ratio < 0.05:
                score += (0.05 - temp_ratio) ** 3
            elif temp_ratio < 0.2:
                score += (0.2 - temp_ratio) * 0.8
            elif temp_ratio < 0.7:
                score += np.log1p(temp_ratio) * 0.5
            else:
                score += np.sqrt(temp_ratio) * 0.3
            temp_ratio = temp_ratio ** 0.75
        extra = 0
        for k in range(2, 7):
            if capacity % k == 0:
                extra += k * 0.1
            else:
                extra -= k * 0.05
        if score < 0.2:
            score += extra * 0.1
        else:
            score -= extra * 0.05
        if score < 0:
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority + 2
    for i in range(len(priorities)):
        if priorities[i] > max_priority * 0.9 and priorities[i] != max_priority + 2:
            priorities[i] *= 0.95
        elif priorities[i] < max_priority * 0.1:
            priorities[i] *= 1.05
    return priorities
